def binary(n):
    # decimal to binary
    return (bin(n).replace("0b", ""))
def decimal(s):
    # binary to decimal
    return (int(s, 2))
def pow2(n):
    # power of a number base 2
    p = 0
    while n > 1:
        n //= 2
        p += 1
    return (p)
def isPrime(n):
    # if  number is prime in √n time
    if (n == 1):
        return (False)
    else:
        root = int(n ** 0.5)
        root += 1
        for i in range(2, root):
            if (n % i == 0):
                return (False)
        return (True)
